        int type;
        scanf("%d", &type);
        if (type == 1) {
            int L, R, P;
            scanf("%d %d %d", &L, &R, &P);
            // Handle rotation
        } else if (type == 2) {
            int L, R;
            scanf("%d %d", &L, &R);
            // Handle reflection
        } else if (type == 3) {
            int X, Y;
            scanf("%d %d", &X, &Y);
            // Handle query
        }
    }
    free(A);
    return 0;
}

